        cross_re = _mm512_mul_pd(sqrt3h,diff_re);
        cross_im = _mm512_mul_pd(sqrt3h,diff_im);

        x0_re = _mm512_add_pd(x0_re,sum_re);
        x0_im = _mm512_add_pd(x0_im,sum_im);

        x1_re = _mm512_sub_pd(ctr_re,cross_im);
